sub_queries.sql:
SELECT District, Senator, Party FROM T48
UNION ALL
SELECT District, Representative, Party FROM T49;

SELECT AVG(CASE WHEN T40.Party != T41.Party THEN 1 ELSE 0 END) AS avg_party_change
FROM T40
JOIN T41 ON T40.District = T41.District;

SELECT District, Previous_Senator, New_Senator, Reason_for_change, Date 
FROM T39 
WHERE Reason_for_change LIKE '%defeated%' OR Reason_for_change LIKE '%retired%' OR Reason_for_change LIKE '%elected%';

SELECT MIN(CAST(First_elected AS REAL)) AS Min_First_Elected, MAX(CAST(First_elected AS REAL)) AS Max_First_Elected
FROM (
  SELECT First_elected FROM T40
  UNION ALL
  SELECT First_Elected AS First_elected FROM T41
);

SELECT District, Previous_Senator, New_Senator, Reason_for_change, Date 
FROM T39 
WHERE Reason_for_change LIKE '%defeated%' OR Reason_for_change LIKE '%retired%' OR Reason_for_change LIKE '%elected%';

SELECT Representative, District, Party, Residence, First_Elected, Term_Limited
FROM T41
WHERE Term_Limited IN ('2014', '2016', '2018', '2020');

SELECT District, Senator, Party, First_elected 
FROM T40 
WHERE Party LIKE '%Dem%' OR Party LIKE '%Rep%';

SELECT Party, COUNT(District) AS Net_Count 
FROM T40 
GROUP BY Party;

SELECT DISTINCT Party FROM T41
UNION
SELECT DISTINCT Party FROM T49;

SELECT Residence FROM T41
UNION
SELECT Residence FROM T49;

SELECT MIN(First_Elected) AS Min_First_Elected, MAX(First_Elected) AS Max_First_Elected
FROM (
    SELECT First_Elected FROM T41
    UNION ALL
    SELECT First_Elected FROM T49
);

SELECT Representative, First_Elected 
FROM T41 
WHERE Term_Limited IS NOT NULL;

SELECT District, Previous_Senator, New_Senator, Reason_for_change, Date 
FROM T39 
WHERE LOWER(Reason_for_change) LIKE '%defeated%' OR LOWER(Reason_for_change) LIKE '%retired%' OR LOWER(Reason_for_change) LIKE '%resigned%';

SELECT District, Previous_Senator, New_Senator, Reason_for_change, Date
FROM T39
WHERE Reason_for_change LIKE '%defeated%' OR Reason_for_change LIKE '%retired%';

SELECT Representative, District, Party, Residence, First_Elected, Term_Limited
FROM T41
WHERE Term_Limited LIKE '%2014%' OR Term_Limited LIKE '%2008%' OR Term_Limited LIKE '%2016%' OR Term_Limited LIKE '%2018%';

SELECT District, Senator, Party, Residence, First_elected, Term_Limited 
FROM T48 
WHERE First_elected BETWEEN 2010 AND 2014;

SELECT District 
FROM T41 
WHERE Term_Limited IS NOT NULL;
